let products = [
  { id: 1, name: 'Laptop', price: 999, inventory: 50 },
  { id: 2, name: 'Phone', price: 699, inventory: 120 },
  { id: 3, name: 'Tablet', price: 499, inventory: 75 },
  { id: 4, name: 'Headphones', price: 199, inventory: 200 },
  { id: 5, name: 'Watch', price: 299, inventory: 30 }
];

let syncCount = 0;

/**
 * Return a snapshot of the current catalog data.
 * In production this would query PostgreSQL / MySQL / etc.
 */
export async function getAllProducts() {
  // Simulate database round-trip latency
  await new Promise(resolve => setTimeout(resolve, 100));
  return products.map(p => ({ ...p }));
}

/**
 * Simulate an upstream ERP/PIM sync that refreshes pricing and inventory.
 * In production this would call an external API, transform the response,
 * and upsert into the database.
 *
 * The operation is intentionally slow (3 s) so the caching / background
 * invalidation behaviour is observable during development.
 */
export async function syncCatalog() {
  // Simulate network + processing delay of a real batch sync
  await new Promise(resolve => setTimeout(resolve, 3_000));

  syncCount++;

  // Simulate new data arriving from an upstream system
  products = products.map(p => ({
    ...p,
    price: Math.round(p.price * (0.9 + Math.random() * 0.2)),   // ±10 %
    inventory: Math.max(0, p.inventory + Math.floor(Math.random() * 40) - 10)
  }));

  return {
    syncedAt: new Date().toISOString(),
    updatedCount: products.length,
    syncNumber: syncCount
  };
}
"}

